#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1005;
int a[N][N],ans[N][N];
struct OPT{short typ,val;inline OPT (short t=0,short v=0){typ=t;val=v;}}opt[3];
inline void Swap(OPT &a,OPT &b){OPT tmp=a;a=b;b=tmp;}
inline void Solve()
{
	int n=read();read();char ch;
	rep(1,n,i)rep(1,n,j)a[i][j]=read();
	opt[0]=OPT(0,n);opt[1]=OPT(1,n);opt[2]=OPT(2,n);
	do ch=getchar(); while(ch<'A'||ch>'Z');
	while(ch<='Z'&&ch>='A')
	{
		switch(ch)
		{
			case 'U': opt[0].val=(opt[0].val==1?n:opt[0].val-1);break;
			case 'D': opt[0].val=(opt[0].val==n?1:opt[0].val+1);break;
			case 'L': opt[1].val=(opt[1].val==1?n:opt[1].val-1);break;
			case 'R': opt[1].val=(opt[1].val==n?1:opt[1].val+1);break;
			case 'I': Swap(opt[1],opt[2]);break;
			case 'C': Swap(opt[0],opt[2]);break;
		}
		ch=getchar();
	}
//	printf("(%d %d) (%d %d) (%d %d)\n",opt[0].typ,opt[0].val,opt[1].typ,opt[1].val,opt[2].typ,opt[2].val);
	rep(1,n,i)rep(1,n,j)
	{
		int pos[3]={i,j,a[i][j]};
		int A=(pos[opt[0].typ]+opt[0].val)%n,B=(pos[opt[1].typ]+opt[1].val)%n,C=(pos[opt[2].typ]+opt[2].val)%n;
		A?0:A=n;B?0:B=n;C?0:C=n;//printf("%d %d %d\n",A,B,C);
		ans[A][B]=C;
	}
//	puts("ANS HERE ::");
	rep(1,n,i){rep(1,n,j)printf("%d ",ans[i][j]);puts("");} 
}
int main()
{
	int T=read();
	while(T--)Solve();
	return 0;
}
